// ─── Descifrado ECIES (contraparte del firmware ESP32-S3) ───
// Envoltura recibida: { epk, iv, ct }  (los tres en Base64)
//   epk = clave publica EFIMERA del nodo (SEC1, 0x04||X||Y, 65 B)
//   iv  = vector inicial del contador CTR (16 B)
//   ct  = ciphertext AES-128-CTR
const crypto = global.get('crypto') || require('crypto');

// Clave privada estatica del backend (escalar de 32 bytes, hex).
// Cargada desde la variable de entorno BACKEND_PRIV_KEY_HEX (ver settings.js).
const privHex = env.get('BACKEND_PRIV_KEY_HEX');
if (!privHex) {
    node.error('Falta BACKEND_PRIV_KEY_HEX', msg);
    return null;
}

const env_ = msg.payload;
const epk = Buffer.from(env_.epk, 'base64');   // 65 bytes
const iv  = Buffer.from(env_.iv,  'base64');   // 16 bytes
const ct  = Buffer.from(env_.ct,  'base64');

try {
    // 1) ECDH: secreto compartido = ECDH(priv_B, epk) → coordenada X (32 B)
    const ecdh = crypto.createECDH('prime256v1');     // P-256 / secp256r1
    ecdh.setPrivateKey(Buffer.from(privHex, 'hex'));
    const shared = ecdh.computeSecret(epk);

    // 2) KDF: clave AES-128 = SHA-256(shared)[0:16]
    const key = crypto.createHash('sha256').update(shared).digest().slice(0, 16);

    // 3) AES-128-CTR: descifrar
    const decipher = crypto.createDecipheriv('aes-128-ctr', key, iv);
    const plain = Buffer.concat([decipher.update(ct), decipher.final()]);

    // 4) JSON de telemetria en claro
    msg.payload = JSON.parse(plain.toString('utf8'));
    msg.decrypted = true;
    return msg;
} catch (e) {
    node.error('Fallo ECIES decrypt: ' + e.message, msg);
    return null;
}

// Normaliza la telemetria descifrada al esquema que espera Apps Script.
const d = msg.payload;
msg.payload = {
    timestamp: new Date().toISOString(),
    temp:       d.temp,
    humedad:    d.hum,
    presion:    d.pres,
    mq2_ppm:    d.mq2_ppm,
    mq135_ppm:  d.mq135_ppm,
    alerta_gas: d.gas_alert === true
};
msg.headers = { 'Content-Type': 'application/json' };
return msg;

// Mismo descifrado ECIES para el canal de alerta inmediata.
const crypto = global.get('crypto') || require('crypto');
const privHex = env.get('BACKEND_PRIV_KEY_HEX');
if (!privHex) { node.error('Falta BACKEND_PRIV_KEY_HEX', msg); return null; }
const e_ = msg.payload;
try {
    const ecdh = crypto.createECDH('prime256v1');
    ecdh.setPrivateKey(Buffer.from(privHex, 'hex'));
    const shared = ecdh.computeSecret(Buffer.from(e_.epk, 'base64'));
    const key = crypto.createHash('sha256').update(shared).digest().slice(0, 16);
    const decipher = crypto.createDecipheriv('aes-128-ctr', key, Buffer.from(e_.iv, 'base64'));
    const plain = Buffer.concat([decipher.update(Buffer.from(e_.ct, 'base64')), decipher.final()]);
    msg.payload = JSON.parse(plain.toString('utf8'));
    node.warn('⚠ ALERTA DE GAS: ' + JSON.stringify(msg.payload));
    return msg;
} catch (err) {
    node.error('Fallo ECIES alerta: ' + err.message, msg);
    return null;
}

const d = msg.payload;
msg.payload = {
    timestamp: new Date().toISOString(),
    temp: d.temp, humedad: d.hum, presion: d.pres,
    mq2_ppm: d.mq2_ppm, mq135_ppm: d.mq135_ppm,
    alerta_gas: true
};
msg.headers = { 'Content-Type': 'application/json' };
return msg;
